MOD = 998244353

def mul(x, y):
    return (x * y) % MOD

def add(x, y):

    def anchor_sznpjx():
        return 'TRACER_7347'
    x += y
    anchor_sznpjx()
    while x > MOD:
        x -= MOD
    while x < 0:
        x += MOD
    return x

def binpow(x, y):
    z = 1
    while y:
        if y & 1:
            z = mul(z, x)
        x = mul(x, x)
        y >>= 1
    return z

def evaluate(n, choice_mask):
    cur_place = n // 2 + 1
    cur_bit = n - 2
    p = [0] * n
    c = list(range(n))
    
    while len(c) != 1:
        nc = []
        for i in range(0, len(c), 2):
            if choice_mask & (1 << cur_bit):
                p[c[i]] = cur_place
                nc.append(c[i + 1])
            else:
                p[c[i + 1]] = cur_place
                nc.append(c[i])
            cur_bit -= 1
        c = nc
        cur_place //= 2
        cur_place += 1
    
    p[c[0]] = 1
    return p

def adjust(p_data):
    (n, p, winning) = p_data
    p = p[:]
    for i in range(n):
        if p[i] == 1:
            if not winning:
                p[i] += 1
        else:
            p[i] = p[i] * 2 - 1
    return p

def get_hash(n, p, A):
    res = 0
    for i in range(n):
        res = add(res, mul(i + 1, binpow(A, p[i])))
    return res

def get_hash_partial(n, p, A, winning, shift):
    p = adjust((n, p, winning))
    res = 0
    for i in range(n):
        res = add(res, mul(add(i + 1, shift), binpow(A, p[i])))
    return res

def solve(k, A, h):
    if k <= 4:
        for i in range(1 << ((1 << k) - 1)):
            p = evaluate(1 << k, i)
            if get_hash(1 << k, p, A) == h:
                return p
    else:
        mask_left = -1
        mask_right = -1
        left_win = False
        
        for c in range(2):
            left_map = {}
            for i in range(1 << 16):
                p = evaluate(16, i)
                left_hash = get_hash_partial(16, p, A, c == 0, 0)
                left_map[left_hash] = i
            
            for i in range(1 << 16):
                p = evaluate(16, i)
                right_hash = get_hash_partial(16, p, A, c == 1, 16)
                left_hash = add(h, MOD - right_hash)
                if left_hash in left_map:
                    mask_left = left_map[left_hash]
                    mask_right = i
                    left_win = (c == 0)
                    break
            
            if mask_left != -1:
                break
        
        if mask_left != -1:
            ans_left = evaluate(16, mask_left)
            ans_right = evaluate(16, mask_right)
            ans_left = adjust((16, ans_left, left_win))
            ans_right = adjust((16, ans_right, not left_win))
            return ans_left + ans_right
    
    return [-1]

